listeners = {
    listener_1 = {
      endpoint_groups = {
        one = {
          endpoint_group_region = "us-west-2"
          destination_configuration = [
            {
              from_port = 80
              protocols = ["TCP"]
              to_port   = 81
            },
            {
              from_port = 443
              protocols = ["TCP"]
              to_port   = 443
            }
          ]

          endpoint_configuration = [for subnet in module.secondary_vpc.public_subnets : { endpoint_id = subnet }]
        }
        two = {
          destination_configuration = [
            {
              from_port = 8080
              protocols = ["TCP"]
              to_port   = 8081
            },
            {
              from_port = 8443
              protocols = ["TCP"]
              to_port   = 8443
            }
          ]

          endpoint_configuration = [for subnet in module.vpc.private_subnets : { endpoint_id = subnet }]
        }
      }


      port_ranges = [
        {
          from_port = 80
          to_port   = 200
        },
        {
          from_port = 8081
          to_port   = 9091
        }
      ]
    }

    listener_2 = {

      endpoint_groups = {
        my_group = {
          destination_configuration = [
            {
              from_port = 8080
              protocols = ["TCP"]
              to_port   = 8081
            },
            {
              from_port = 8091
              protocols = ["TCP"]
              to_port   = 8091
            }
          ]

          endpoint_configuration = [for subnet in module.vpc.private_subnets : { endpoint_id = subnet }]
        }
      }

      port_ranges = [
        {
          from_port = 201
          to_port   = 300
        },
        {
          from_port = 301
          to_port   = 400
        }
      ]
    }
  }

listeners = {
    listener_1 = {
      client_affinity = "SOURCE_IP"

      endpoint_groups = {
        my_group_1 = {
          health_check_port             = 80
          health_check_protocol         = "HTTP"
          health_check_path             = "/"
          health_check_interval_seconds = 10
          health_check_timeout_seconds  = 5
          healthy_threshold_count       = 2
          unhealthy_threshold_count     = 2
          traffic_dial_percentage       = 100

          # Health checks will show as unhealthy in this example because there
          # are obviously no healthy instances in the target group
          endpoint_configuration = [{
            client_ip_preservation_enabled = true
            endpoint_id                    = module.alb.lb_arn
            weight                         = 50
            }, {
            client_ip_preservation_enabled = false
            endpoint_id                    = module.alb.lb_arn
            weight                         = 50
          }]

          port_override = [{
            endpoint_port = 82
            listener_port = 80
            }, {
            endpoint_port = 8082
            listener_port = 8080
            }, {
            endpoint_port = 8083
            listener_port = 8081
          }]
        }
        my_group_2 = {
          endpoint_group_region         = local.secondary_region
          health_check_port             = 80
          health_check_protocol         = "HTTP"
          health_check_path             = "/"
          health_check_interval_seconds = 10
          health_check_timeout_seconds  = 5
          healthy_threshold_count       = 2
          unhealthy_threshold_count     = 2
          traffic_dial_percentage       = 100

          # Health checks will show as unhealthy in this example because there
          # are obviously no healthy instances in the target group
          endpoint_configuration = [{
            client_ip_preservation_enabled = true
            endpoint_id                    = module.secondary_alb.lb_arn
            weight                         = 50
            }, {
            client_ip_preservation_enabled = false
            endpoint_id                    = module.secondary_alb.lb_arn
            weight                         = 50
          }]

          port_override = [{
            endpoint_port = 82
            listener_port = 80
            }, {
            endpoint_port = 8082
            listener_port = 8080
            }, {
            endpoint_port = 8083
            listener_port = 8081
          }]
        }
      }

      port_ranges = [
        {
          from_port = 80
          to_port   = 81
        },
        {
          from_port = 8080
          to_port   = 8081
        }
      ]
      protocol = "TCP"
    }

    listener_2 = {
      port_ranges = [
        {
          from_port = 443
          to_port   = 443
        },
        {
          from_port = 8443
          to_port   = 8443
        }
      ]
      protocol = "TCP"
    }

    listener_3 = {
      port_ranges = [
        {
          from_port = 53
          to_port   = 53
        }
      ]
      protocol = "UDP"
    }
  }
